/* ── ELEMENTS ── */
const landing       = document.getElementById('landing');
const victoryScreen = document.getElementById('victory-screen');
const cmdInput      = document.getElementById('cmd-input');
const hintText      = document.getElementById('hint-text');
const photoUpload   = document.getElementById('photo-upload');
const photoImg      = document.getElementById('photo-img');
const photoPlaceholder = document.getElementById('photo-placeholder');
const restartBtn    = document.getElementById('restart-btn');
const confettiCanvas = document.getElementById('confetti-canvas');

/* ── TERMINAL INPUT ── */
cmdInput.focus();

cmdInput.addEventListener('keydown', (e) => {
  if (e.key !== 'Enter') return;

  const raw = cmdInput.value.trim();
  const normalized = raw.replace(/\s/g, '').toLowerCase();

  if (normalized === 'console.log(vencedor)') {
    triggerVictory();
  } else if (raw.length > 0) {
    hintText.textContent = `Uncaught ReferenceError: ${raw} is not defined`;
    hintText.classList.add('error');
    cmdInput.value = '';
    setTimeout(() => {
      hintText.textContent = '';
      hintText.classList.remove('error');
    }, 2500);
  }
});

/* ── RESTART ── */
restartBtn.addEventListener('click', restart);

function restart() {
  victoryScreen.style.display = 'none';
  landing.style.display = 'flex';
  cmdInput.value = '';
  cmdInput.focus();
  stopMusic();
}

/* ── TRANSITION ── */
function triggerVictory() {
  landing.style.display = 'none';
  victoryScreen.style.display = 'flex';
  startConfetti();
  playBrasil();
}

/* ── CONFETTI ── */
let confettiFrame = null;

function startConfetti() {
  const canvas = confettiCanvas;
  const ctx = canvas.getContext('2d');

  function resize() {
    canvas.width  = window.innerWidth;
    canvas.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  const COLORS = [
    '#c9a84c', '#f0d78c', '#4fc3f7', '#28c840',
    '#ff5f57', '#e040fb', '#00e5ff', '#fff176',
    '#ffb300', '#40c4ff',
  ];

  const pieces = Array.from({ length: 140 }, () => ({
    x:     Math.random() * canvas.width,
    y:     Math.random() * -canvas.height,
    w:     6 + Math.random() * 9,
    h:     11 + Math.random() * 7,
    color: COLORS[Math.floor(Math.random() * COLORS.length)],
    rot:   Math.random() * Math.PI * 2,
    rotV:  (Math.random() - 0.5) * 0.13,
    vx:    (Math.random() - 0.5) * 2.8,
    vy:    2.8 + Math.random() * 3.2,
    shape: Math.random() > 0.5 ? 'rect' : 'circle',
  }));

  let elapsed = 0;
  const MAX_FRAMES = 480; // ~8 seconds at 60fps

  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    elapsed++;

    pieces.forEach((p) => {
      p.x   += p.vx;
      p.y   += p.vy;
      p.rot += p.rotV;

      if (p.y > canvas.height + 20) {
        p.y = -20;
        p.x = Math.random() * canvas.width;
      }

      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate(p.rot);
      ctx.fillStyle = p.color;

      if (p.shape === 'rect') {
        ctx.fillRect(-p.w / 2, -p.h / 2, p.w, p.h);
      } else {
        ctx.beginPath();
        ctx.arc(0, 0, p.w / 2, 0, Math.PI * 2);
        ctx.fill();
      }

      ctx.restore();
    });

    if (elapsed < MAX_FRAMES) {
      confettiFrame = requestAnimationFrame(draw);
    } else {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
    }
  }

  if (confettiFrame) cancelAnimationFrame(confettiFrame);
  draw();
}

/* ── ÁUDIO — vinheta gol do Brasil 1994 ── */
let audio = null;

function playBrasil() {
  try {
    audio = new Audio('data:audio/mpeg;base64,');
    audio.volume = 0.85;
    audio.play();
  } catch (err) {
    console.warn('Áudio indisponível:', err);
  }
}

function stopMusic() {
  if (audio) {
    audio.pause();
    audio.currentTime = 0;
    audio = null;
  }
  if (confettiFrame) {
    cancelAnimationFrame(confettiFrame);
    confettiFrame = null;
  }
}